  1	import * as React from 'react';
  2	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  4	import { getValidatedProp } from '@odf/shared/utils';
  5	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  6	import { t_color_blue_40 as blueInfoColor } from '@patternfly/react-tokens/dist/js/t_color_blue_40';
  7	import * as _ from 'lodash-es';
  8	import { TFunction } from 'react-i18next';
  9	import {
 10	  FormGroup,
 11	  FormSelect,
 12	  FormSelectOption,
 13	  Button,
 14	  FormHelperText,
 15	  HelperText,
 16	  HelperTextItem,
 17	  ValidatedOptions,
 18	  Icon,
 19	} from '@patternfly/react-core';
 20	import { PencilAltIcon } from '@patternfly/react-icons';
 21	import { ProviderStateMap } from '../../constants';
 22	import {
 23	  VaultConfig,
 24	  ProviderNames,
 25	  VaultAuthMethods,
 26	  KmsEncryptionLevel,
 27	  VaultAuthMethodMapping,
 28	} from '../../types';
 29	import { NameAddrPort } from './name-address-port';
 30	import { KMSConfigureProps, EncryptionDispatch } from './providers';
 31	import { kmsConfigValidation, isLengthUnity } from './utils';
 32	import {
 33	  VaultTokenConfigure,
 34	  VaultServiceAccountConfigure,
 35	  VaultAuthMethodProps,
 36	} from './vault-auth-methods';
 37	import './kms-config.scss';
 38	
 39	const AdvancedVaultModal = React.lazy(
 40	  () => import('../../modals/advanced-kms-modal/advanced-vault-modal')
 41	);
 42	
 43	export const VaultConfigure: React.FC<KMSConfigureProps> = ({
 44	  state,
 45	  dispatch,
 46	  className,
 47	  isWizardFlow,
 48	  isMCG,
 49	  systemNamespace,
 50	}) => {
 51	  const { t } = useCustomTranslation();
 52	
 53	  const launchModal = useModal();
 54	
 55	  const vaultState = useDeepCompareMemoize(
 56	    state.kms.providerState,
 57	    true
 58	  ) as VaultConfig;
 59	  const vaultStateClone: VaultConfig = React.useMemo(
 60	    () => _.cloneDeep(vaultState),
 61	    [vaultState]
 62	  );
 63	
 64	  const { encryption } = state;
 65	  const isScEncryption = encryption.storageClass;
 66	
 67	  const openAdvancedModal = () =>
 68	    launchModal(AdvancedVaultModal, {
 69	      state,
 70	      dispatch,
 71	      isWizardFlow,
 72	      systemNamespace,
 73	    });
 74	
 75	  const updateVaultState = React.useCallback(
 76	    (vaultConfig: VaultConfig) =>
 77	      dispatch({
 78	        type: 'securityAndNetwork/setKmsProviderState',
 79	        payload: vaultConfig,
 80	      }),
 81	    [dispatch]
 82	  );
 83	
 84	  const setAuthValue = React.useCallback(
 85	    (authValue: string) => {
 86	      vaultStateClone.authValue.value = authValue;
 87	      vaultStateClone.authValue.valid = authValue !== '';
 88	      updateVaultState(vaultStateClone);
 89	    },
 90	    [updateVaultState, vaultStateClone]
 91	  );
 92	
 93	  const setAuthMethod = React.useCallback(
 94	    (authMethod: VaultAuthMethods) => {
 95	      if (!!vaultStateClone.authMethod) {
 96	        vaultStateClone.authValue =
 97	          ProviderStateMap[ProviderNames.VAULT].authValue;
 98	      }
 99	      vaultStateClone.authMethod = authMethod;
100	      updateVaultState(vaultStateClone);
101	    },
102	    [updateVaultState, vaultStateClone]
103	  );
104	
105	  const filteredVaultAuthMethodMapping = React.useMemo(
106	    () =>
107	      Object.values(VaultAuthMethodMapping).filter(
108	        (authMethod) =>
109	          (encryption.clusterWide || isMCG
110	            ? authMethod.supportedEncryptionType.includes(
111	                KmsEncryptionLevel.CLUSTER_WIDE
112	              )
113	            : false) ||
114	          (encryption.storageClass
115	            ? authMethod.supportedEncryptionType.includes(
116	                KmsEncryptionLevel.STORAGE_CLASS
117	              )
118	            : false)
119	      ),
120	    [encryption.clusterWide, encryption.storageClass, isMCG]
121	  );
122	
123	  const vaultAuthMethods = React.useMemo(
124	    () => filteredVaultAuthMethodMapping.map((authMethod) => authMethod.value),
125	    [filteredVaultAuthMethodMapping]
126	  );
127	
128	  React.useEffect(() => {
129	    if (!vaultAuthMethods.includes(vaultState.authMethod)) {
130	      if (vaultAuthMethods.includes(VaultAuthMethods.KUBERNETES)) {
131	        // From 4.10 kubernetes is default auth method
132	        setAuthMethod(VaultAuthMethods.KUBERNETES);
133	      } else {
134	        // upto 4.9 token is the default auth method
135	        setAuthMethod(VaultAuthMethods.TOKEN);
136	      }
137	    }
138	  }, [setAuthMethod, vaultAuthMethods, vaultState.authMethod]);
139	
140	  const getValidatedAuthMethodProp = getValidatedProp(!vaultState.authMethod);
141	
142	  return (
143	    <>
144	      <FormGroup
145	        fieldId="authentication-method"
146	        label={t('Authentication method')}
147	        className={`${className}__form-body`}
148	        isRequired
149	      >
150	        <FormSelect
151	          value={vaultState.authMethod}
152	          onChange={(_ev, value) => setAuthMethod(value as VaultAuthMethods)}
153	          id="authentication-method"
154	          name="authentication-method"
155	          aria-label={t('authentication-method')}
156	          isDisabled={isLengthUnity(vaultAuthMethods)}
157	          data-test="vault-config-auth-method"
158	        >
159	          {filteredVaultAuthMethodMapping.map((authMethod) => (
160	            <FormSelectOption
161	              value={authMethod.value}
162	              label={authMethod.name}
163	              key={authMethod.name}
164	            />
165	          ))}
166	        </FormSelect>
167	        <FormHelperText>
168	          <HelperText>
169	            <HelperTextItem variant={getValidatedAuthMethodProp}>
170	              {getValidatedAuthMethodProp === ValidatedOptions.error &&
171	                t('This is a required field')}
172	            </HelperTextItem>
173	          </HelperText>
174	        </FormHelperText>
175	      </FormGroup>
176	      <ValutConnectionForm
177	        {...{
178	          t,
179	          isScEncryption,
180	          vaultState,
181	          className,
182	          isWizardFlow,
183	          dispatch,
184	          updateVaultState,
185	          setAuthValue,
186	          openAdvancedModal,
187	        }}
188	      />
189	    </>
190	  );
191	};
192	
193	const ValutConnectionForm: React.FC<ValutConnectionFormProps> = ({
194	  t,
195	  isScEncryption,
196	  vaultState,
197	  className,
198	  isWizardFlow,
199	  dispatch,
200	  updateVaultState,
201	  setAuthValue,
202	  openAdvancedModal,
203	}) => {
204	  const vaultStateClone: VaultConfig = _.cloneDeep(vaultState);
205	  const Component: React.FC<VaultAuthMethodProps> =
206	    vaultState.authMethod === VaultAuthMethods.TOKEN
207	      ? VaultTokenConfigure
208	      : VaultServiceAccountConfigure;
209	
210	  React.useEffect(() => {
211	    // only need to pass authValue for wizard flow
212	    const validAuthValue: boolean = isWizardFlow
213	      ? vaultState.authValue?.valid && vaultState.authValue?.value !== ''
214	      : true;
215	    const hasHandled: boolean =
216	      validAuthValue && kmsConfigValidation(vaultState, ProviderNames.VAULT);
217	    if (vaultState.hasHandled !== hasHandled) {
218	      dispatch({
219	        type: 'securityAndNetwork/setKmsProviderState',
220	        payload: {
221	          ...vaultState,
222	          hasHandled,
223	        },
224	      });
225	    }
226	  }, [dispatch, vaultState, isWizardFlow]);
227	
228	  return (
229	    <>
230	      <NameAddrPort
231	        className={className}
232	        kmsState={vaultState}
233	        kmsStateClone={vaultStateClone}
234	        updateKmsState={updateVaultState}
235	        canAcceptIP={false}
236	      />
237	      {isWizardFlow && (
238	        <Component
239	          {...{
240	            t,
241	            className: `${className}__form-body`,
242	            vaultState,
243	            setAuthValue,
244	            isScEncryption,
245	          }}
246	        />
247	      )}
248	      <Button
249	        variant="link"
250	        className={`${className}__form-body`}
251	        onClick={openAdvancedModal}
252	        data-test="kms-advanced-settings-link"
253	      >
254	        {t('Advanced settings')}{' '}
255	        {(vaultState.backend ||
256	          vaultState.caCert ||
257	          vaultState.tls ||
258	          vaultState.clientCert ||
259	          vaultState.clientKey ||
260	          vaultState.providerNamespace) && (
261	          <Icon size="sm">
262	            <PencilAltIcon data-test="edit-icon" color={blueInfoColor.value} />
263	          </Icon>
264	        )}
265	      </Button>
266	    </>
267	  );
268	};
269	
270	export type ValutConnectionFormProps = {
271	  isScEncryption?: boolean;
272	  vaultState: VaultConfig;
273	  className: string;
274	  infraType?: string;
275	  isWizardFlow?: boolean;
276	  t: TFunction;
277	  dispatch: EncryptionDispatch;
278	  updateVaultState: (VaultConfig) => void;
279	  setAuthValue: (string) => void;
280	  openAdvancedModal: () => void;
281	};

